<?php
session_start();require_once '../config/base.php';
if(!isset($_SESSION['admin_id'])){header('Location: '.BASE_URL.'/login.php');exit;}
require_once '../config/db.php';
if(isset($_GET['delete'])){$id=intval($_GET['delete']);$pdo->prepare("DELETE FROM registrations WHERE event_id=?")->execute([$id]);$pdo->prepare("DELETE FROM events WHERE id=?")->execute([$id]);header('Location: '.BASE_URL.'/admin/manage_events.php?msg=deleted');exit;}
$msg=$_GET['msg']??'';
$evs=$pdo->query("SELECT e.*,(SELECT COUNT(*) FROM registrations r WHERE r.event_id=e.id) AS rc FROM events e ORDER BY e.event_date DESC")->fetchAll();
?>
