none;display:inline-block;transition:all .3s;}.btn-add:hover{transform:translateY(-2px);}.alert{padding:.875rem 1rem;border-radius:10px;margin-bottom:1.5rem;font-size:.875rem;}.as{background:rgba(110,231,183,.08);border:1px solid rgba(110,231,183,.2);color:var(--accent);}.tw{background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;}table{width:100%;border-collapse:collapse;}th{padding:.875rem 1.25rem;text-align:left;font-size:.72rem;font-weight:600;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;border-bottom:1px solid var(--border);background:rgba(255,255,255,.02);}td{padding:1rem 1.25rem;border-bottom:1px solid rgba(255,255,255,.04);font-size:.875rem;}tr:last-child td{border:none;}tr:hover td{background:rgba(255,255,255,.02);}.tag{display:inline-block;padding:.2rem .6rem;border-radius:100px;font-size:.7rem;font-weight:600;}.tg{background:rgba(110,231,183,.1);color:var(--accent);}.axs{display:flex;gap:.4rem;}.bxs{padding:.35rem .8rem;border-radius:7px;font-size:.75rem;font-weight:600;text-decoration:none;border:none;cursor:pointer;transition:all .2s;display:inline-block;}.be{background:rgba(129,140,248,.1);color:var(--accent2);}.be:hover{background:rgba(129,140,248,.25);}.bd{background:rgba(248,113,113,.1);color:var(--error);}.bd:hover{background:rgba(248,113,113,.25);}.empty{text-align:center;padding:4rem;color:var(--muted);}@media(max-width:768px){.sidebar{display:none;}.main{margin-left:0;}}</style></head><body>
