  <div class="ph"><h1>Manage Events</h1><a href="<?=BASE_URL?>/admin/add_event.php" class="btn-add">+ Add New Event</a></div>
  <?php if($msg==='deleted'): ?><div class="alert as">✅ Event deleted.</div><?php elseif($msg==='added'): ?><div class="alert as">✅ Event added.</div><?php elseif($msg==='updated'): ?><div class="alert as">✅ Event updated.</div><?php endif; ?>
  <div class="tw"><?php if(empty($evs)): ?><div class="empty"><div style="font-size:3rem;margin-bottom:1rem">📅</div><h3 style="font-family:'Syne',sans-serif">No Events Yet</h3></div>
  <?php else: ?><table><thead><tr><th>#</th><th>Event Title</th><th>Category</th><th>Date</th><th>Location</th><th>Price</th><th>Reg.</th><th>Actions</th></tr></thead><tbody>
  <?php foreach($evs as $i=>$ev): ?><tr style="<?=strtotime($ev['event_date'])<time()?'opacity:.5':''?>"><td style="color:var(--muted)"><?=$i+1?></td><td><div style="font-weight:600;max-width:200px"><?=htmlspecialchars($ev['title'])?></div><?php if($ev['organizer']): ?><div style="font-size:.72rem;color:var(--muted)">by <?=htmlspecialchars($ev['organizer'])?></div><?php endif;?></td><td><span class="tag tg"><?=htmlspecialchars($ev['category'])?></span></td><td style="color:var(--muted);font-size:.82rem"><?=date('M j, Y',strtotime($ev['event_date']))?></td><td style="color:var(--muted);font-size:.82rem"><?=htmlspecialchars($ev['location']??'—')?></td><td style="font-weight:600;color:<?=($ev['price']==0)?'var(--accent)':'#FBBF24'?>"><?=(!$ev['price']||$ev['price']==0)?'Free':'₹'.number_format($ev['price'])?></td><td style="font-family:'Syne',sans-serif;font-weight:700;color:var(--accent)"><?=$ev['rc']?>/<?=$ev['max_participants']?></td><td><div class="axs"><a href="<?=BASE_URL?>/admin/edit_event.php?id=<?=$ev['id']?>" class="bxs be">✏️ Edit</a><a href="<?=BASE_URL?>/admin/manage_events.php?delete=<?=$ev['id']?>" class="bxs bd" onclick="return confirm('Delete \'<?=htmlspecialchars(addslashes($ev['title']))?>\'?')">🗑️ Del</a></div></td></tr><?php endforeach;?></tbody></table><?php endif;?>
  </div>
</main></div></body></html>